let excludedPsp = dynamic(["TestEmdTpp", "MDC Test"]);

let excludedTpp =
    TppDataSnapshot
    | where business_name in~ (excludedPsp)
    | distinct tpp_id;

let excludedEntity =
    TppDataSnapshot
    | where business_name in~ (excludedPsp)
    | distinct entity_id;

let sentFiltrato =
    MessageSnapshot
    | where $__timeFilter(window_start)
    | where message_state == "SENT"
    | join kind=leftanti excludedEntity on entity_id;

let known_origins =
    sentFiltrato
    | summarize by origin_id;

let messaggiAccettati = toscalar(
    sentFiltrato
    | count
);

let finalizedFiltrato =
    FinalizedMessageSnapshot
    | where $__timeFilter(window_start)
    | where origin_id in (known_origins)
    | join kind=leftanti excludedTpp on tpp_id;

let pagamentiCompletati = toscalar(
    finalizedFiltrato
    | summarize arg_max(window_start, tpp_id) by origin_id
    | summarize dcount(origin_id)
);

let pspAttivi = toscalar(
    finalizedFiltrato
    | summarize by tpp_id
    | count
);

print ['Tasso di Conversione Pagamento Totale'] =
    iff(messaggiAccettati == 0 or pspAttivi == 0, 0.0,
        round((100.0 * todouble(pagamentiCompletati) / todouble(messaggiAccettati)) / todouble(pspAttivi), 2))

let excludedPsp = dynamic(["TestEmdTpp", "MDC Test"]);

let pspTotali = toscalar(
    TppDataSnapshot
    | where business_name !in~ (excludedPsp)
    | count
);

let pspAttivi = toscalar(
    TppDataSnapshot
    | where business_name !in~ (excludedPsp)
    | where state == true
    | count
);

print ['PSP Attivi / Totali'] = strcat(tostring(pspAttivi), " / ", tostring(pspTotali))

let known_origins =
    MessageSnapshot
    | where message_state == "SENT"
    | summarize by origin_id;
let dayRange =
    range Day from startofday($__timeFrom) to startofday($__timeTo) step 1d
    | project Day;
let volume_per_day =
    MessageVolumeSnapshot
    | where $__timeFilter(window_start)
    | summarize Sent = sum(message_sent_count), Discarded = sum(message_discarded_count)
      by Day = bin(window_start, 1d);
let inviate_per_day =
    MessageSnapshot
    | where message_state == "SENT"
    | where $__timeFilter(window_start)
    | summarize Inviate = dcount(origin_id) by Day = bin(window_start, 1d);
let lette_per_day =
    RetrievalIdVolumeSnapshot
    | where $__timeFilter(window_start)
    | where origin_id in (known_origins)
    | summarize Lette = dcount(origin_id) by Day = bin(window_start, 1d);
dayRange
| join kind=leftouter volume_per_day on Day
| join kind=leftouter inviate_per_day on Day
| join kind=leftouter lette_per_day on Day
| extend Sent = coalesce(Sent, 0), Discarded = coalesce(Discarded, 0),
         Inviate = coalesce(Inviate, 0), Lette = coalesce(Lette, 0)
| extend ['Tasso di Accettazione (%)'] = iff(Sent + Discarded == 0, 0.0, round(100.0 * Sent / (Sent + Discarded), 2))
| extend ['Tasso di Lettura (%)'] = iff(Inviate == 0, 0.0, round(100.0 * Lette / Inviate, 2))
| project window_start = Day, ['Tasso di Accettazione (%)'], ['Tasso di Lettura (%)']
| order by window_start asc

let excludedPsp = dynamic(["TestEmdTpp", "MDC Test"]);

let payment_map =
    MessageSnapshot
    | summarize arg_max(window_start, associated_payment) by origin_id;
    // Nessun timeFilter per prendere tutto lo storico

let known_origins =
    MessageSnapshot
    | where message_state == "SENT"
    | summarize by origin_id;

let perfezionate_con_pagamento =
    FinalizedMessageSnapshot
    | where $__timeFilter(window_start)
    | where origin_id in (known_origins)
    | summarize arg_max(window_start, tpp_id) by origin_id
    | join kind=inner payment_map on origin_id
    | where associated_payment == true
    | summarize ['Perf. Con Pagamento'] = dcount(origin_id) by tpp_id;

let pagate =
    PaymentAttemptSnapshot
    | where $__timeFilter(window_start)
    | summarize ['Notifiche Pagate'] = dcount(origin_id) by tpp_id;

let tutte_le_tpp =
    TppDataSnapshot
    | where business_name !in~ (excludedPsp)
    | summarize by tpp_id, PSP = business_name;

tutte_le_tpp
| join kind=leftouter perfezionate_con_pagamento on tpp_id
| join kind=leftouter pagate on tpp_id
| extend ['Perf. Con Pagamento'] = coalesce(['Perf. Con Pagamento'], 0)
| extend ['Notifiche Pagate']    = coalesce(['Notifiche Pagate'], 0)
| extend ['Tasso di Pagamento']  = iff(['Perf. Con Pagamento'] == 0, 0.0, 
                                            round(100.0 * ['Notifiche Pagate'] / ['Perf. Con Pagamento'], 2))
| project
    PSP,
    ['Notifiche Pagate'],
    ['Tasso di Pagamento']
| order by ['Tasso di Pagamento'] desc
